parameters.jsCode:
// Fan out the incoming image_urls array into one item per image.
// Carry post_id and approval_number on every item for downstream access.
const input = $input.first().json;
const urls = input.image_urls || [];
const postId = input.post_id;
const approvalNumber = input.approval_number;

if (!Array.isArray(urls) || urls.length === 0) {
  throw new Error('Sub-workflow input missing image_urls array');
}

return urls.map((entry) => ({
  json: {
    slide_index: entry.index,
    source_url: entry.url,
    post_id: postId,
    approval_number: approvalNumber,
  }
}));

// Generate date-prefixed UUID blob name.
// Detect extension from source URL ending, default to .jpg.
// UUID v4 generated without require('crypto') because the n8n task runner
// sandbox disallows that module. Math.random is sufficient for blob-name
// uniqueness at our volume (collision probability << 10^-18 per post).
function uuidV4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

const now = new Date();
const y = now.getUTCFullYear();
const m = String(now.getUTCMonth() + 1).padStart(2, '0');
const d = String(now.getUTCDate()).padStart(2, '0');

const sourceUrl = $json.source_url || '';
const pathOnly = sourceUrl.split('?')[0].toLowerCase();
let ext = 'jpg';
let contentType = 'image/jpeg';
if (pathOnly.endsWith('.png')) {
  ext = 'png';
  contentType = 'image/png';
} else if (pathOnly.endsWith('.webp')) {
  ext = 'webp';
  contentType = 'image/webp';
}

const blobName = y + '/' + m + '/' + d + '/' + uuidV4() + '.' + ext;

// Preserve binary from the HTTP GET upstream — the HTTP PUT needs `data`
// attached to the item. Code nodes do not forward binary automatically.
return {
  json: {
    ...$json,
    blob_name: blobName,
    content_type: contentType,
  },
  binary: $binary,
};

// Construct the public blob URL from env vars + blob_name.
// Pull fields from the Build blob name node upstream because the HTTP PUT
// response replaces $json with only {headers, statusCode, statusMessage}.
// Env access is allowed here because N8N_BLOCK_ENV_ACCESS_IN_NODE=false
// on this Container App revision (verified 2026-04-16).
const ctx = $('🔧 Build blob name').item.json;
const account = $env.AZURE_STORAGE_ACCOUNT;
const container = $env.AZURE_CONTAINER;

return {
  json: {
    blob_url: 'https://' + account + '.blob.core.windows.net/' + container + '/' + ctx.blob_name,
    blob_name: ctx.blob_name,
    slide_index: ctx.slide_index,
    post_id: ctx.post_id,
    approval_number: ctx.approval_number,
    source_url: ctx.source_url,
    content_type: ctx.content_type,
    put_status: $json.statusCode,
  },
};

// Aggregate all per-item blob URLs into a single output item, sorted by slide_index.
// Source the data from the Build blob URL node (not $input, because the HEAD
// verify node replaces $json with response headers).
const items = $('🔧 Build blob URL').all();
const postId = items[0]?.json?.post_id || null;

const blobUrls = items
  .map(it => ({
    index: it.json.slide_index,
    url: it.json.blob_url,
  }))
  .filter(b => b.url)
  .sort((a, b) => a.index - b.index);

return [{
  json: {
    blob_urls: blobUrls,
    post_id: postId,
  }
}];
